mapper.sql:
/* 멤버십 등록 */ SELECT 'MEMBERSHIP' AS type, COALESCE(DATE_FORMAT(mm.payment_date, '%Y-%m-%d'), mm.start_date) AS date, CONCAT(ms.name, ' 멤버십 등록') AS title, CONCAT(mm.start_date, ' ~ ', mm.expiry_date, ' / ', mm.total_count, '회') AS detail, mm.status AS status FROM complex_member_memberships mm JOIN memberships ms ON ms.seq = mm.membership_seq WHERE mm.member_seq = #{memberSeq}
UNION ALL
/* 연기 요청 */ SELECT 'POSTPONEMENT' AS type, DATE_FORMAT(p.created_date, '%Y-%m-%d') AS date, CONCAT('수업 연기 요청', IF(p.current_class != '', CONCAT(' (', p.current_class, ')'), '')) AS title, CONCAT(p.start_date, ' ~ ', p.end_date, ' / ', p.reason) AS detail, '대기' AS status FROM complex_postponement_requests p WHERE p.member_seq = #{memberSeq}
UNION ALL
/* 연기 처리 (승인/반려) */ SELECT 'POSTPONEMENT_RESULT' AS type, DATE_FORMAT(p.last_update_date, '%Y-%m-%d') AS date, CONCAT('수업 연기 ', p.status, IF(p.current_class != '', CONCAT(' (', p.current_class, ')'), '')) AS title, CASE WHEN p.status = '반려' AND p.reject_reason IS NOT NULL THEN CONCAT('반려 사유: ', p.reject_reason) ELSE CONCAT(p.start_date, ' ~ ', p.end_date) END AS detail, p.status AS status FROM complex_postponement_requests p WHERE p.member_seq = #{memberSeq} AND p.status != '대기' AND p.last_update_date IS NOT NULL
UNION ALL
/* 환불 요청 */ SELECT 'REFUND' AS type, DATE_FORMAT(r.created_date, '%Y-%m-%d') AS date, CONCAT(r.membership_name, ' 환불 요청') AS title, r.reason AS detail, '대기' AS status FROM complex_refund_requests r WHERE r.member_seq = #{memberSeq}
UNION ALL
/* 환불 처리 (승인/반려) */ SELECT 'REFUND_RESULT' AS type, DATE_FORMAT(r.last_update_date, '%Y-%m-%d') AS date, CONCAT(r.membership_name, ' 환불 ', r.status) AS title, CASE WHEN r.status = '반려' AND r.reject_reason IS NOT NULL THEN CONCAT('반려 사유: ', r.reject_reason) ELSE NULL END AS detail, r.status AS status FROM complex_refund_requests r WHERE r.member_seq = #{memberSeq} AND r.status != '대기' AND r.last_update_date IS NOT NULL
UNION ALL
/* 출석 기록 */ SELECT 'ATTENDANCE' AS type, a.attendance_date AS date, CONCAT(c.name, ' 수업') AS title, a.note AS detail, a.status AS status FROM complex_member_attendance a JOIN complex_member_memberships mm ON mm.seq = a.member_membership_seq JOIN complex_classes c ON c.seq = a.class_seq WHERE mm.member_seq = #{memberSeq}

