SELECT * FROM (

) t
ORDER BY t.date DESC, t.type
LIMIT #{size} OFFSET #{offset}

mapper.sql:
/* 스태프 등록 */ SELECT 'STAFF_REGISTER' AS type, COALESCE(s.join_date, DATE_FORMAT(s.created_date, '%Y-%m-%d')) AS date, CONCAT(s.name, ' 스태프 등록') AS title, CONCAT('담당과목: ', COALESCE(s.subject, '-')) AS detail, s.status AS status FROM complex_staffs s WHERE s.seq = #{staffSeq}
UNION ALL
/* 상태 변경 */ SELECT 'STATUS_CHANGE' AS type, DATE_FORMAT(sl.created_date, '%Y-%m-%d') AS date, CONCAT('상태 변경: ', sl.from_status, ' → ', sl.to_status) AS title, NULL AS detail, sl.to_status AS status FROM complex_staff_status_logs sl WHERE sl.staff_seq = #{staffSeq}
UNION ALL
/* 출석 기록 */ SELECT 'ATTENDANCE' AS type, a.attendance_date AS date, CONCAT(c.name, ' 수업') AS title, NULL AS detail, a.status AS status FROM complex_staff_attendance a JOIN complex_classes c ON c.seq = a.class_seq WHERE a.staff_seq = #{staffSeq}
UNION ALL
/* 수업 배정/해제 */ SELECT 'CLASS_ASSIGN' AS type, DATE_FORMAT(cl.created_date, '%Y-%m-%d') AS date, CONCAT(c.name, ' 수업 ', CASE cl.action WHEN 'ASSIGN' THEN '배정' ELSE '해제' END) AS title, COALESCE(t.name, '') AS detail, cl.action AS status FROM complex_staff_class_logs cl JOIN complex_classes c ON c.seq = cl.class_seq LEFT JOIN complex_class_time_slots t ON t.seq = c.time_slot_seq WHERE cl.staff_seq = #{staffSeq}
UNION ALL
/* 정보 변경 */ SELECT 'INFO_CHANGE' AS type, DATE_FORMAT(lg.created_date, '%Y-%m-%d') AS date, CONCAT(lg.field_name, ' 변경') AS title, CONCAT(COALESCE(lg.old_value, '(없음)'), ' → ', COALESCE(lg.new_value, '(없음)')) AS detail, '변경' AS status FROM complex_staff_change_logs lg WHERE lg.staff_seq = #{staffSeq} AND lg.change_type = 'INFO_CHANGE'
UNION ALL
/* 환불정보 변경 */ SELECT 'REFUND_CHANGE' AS type, DATE_FORMAT(lg.created_date, '%Y-%m-%d') AS date, CONCAT('환불정보 ', lg.field_name, ' 변경') AS title, CONCAT(COALESCE(lg.old_value, '(없음)'), ' → ', COALESCE(lg.new_value, '(없음)')) AS detail, '변경' AS status FROM complex_staff_change_logs lg WHERE lg.staff_seq = #{staffSeq} AND lg.change_type = 'REFUND_CHANGE'

